INSERT INTO `blog` VALUES (NULL, '无题',NULL, '### Django2.1.2/Python3.6 \r\n#### 报错内容：Data too long for column \'object_repr\' at row 1\r\n#### 出错原因：数据中转时要先将text数据保存至django_admin_log的object_repr列，而object_repr列默认为varchar(200)，故报错\r\n#### 解决办法：xadmin/models.py 类 class Log(models.Model)中，修改为\r\n```\r\nobject_repr = models.TextField(_(\'object repr\'))\r\n```\r\n#### 最后记得makemigrations和migrate', 'Django', 'Emiya', '2018-11-09 11:53:37.448368', '2019-09-06 01:44:18.619771', 54, 0);
